const express = require('express');
const {
  createProduct,
  deleteProduct,
  getProductBySlug,
  listProducts,
  listProductsByCategory,
  searchCatalog,
  updateProduct,
} = require('../controllers/productController');
const { requireAdmin } = require('../middlewares/requireAdmin');
const { asyncHandler } = require('../utils/asyncHandler');

const router = express.Router();

router.get('/', asyncHandler(listProducts));
router.get('/search', asyncHandler(searchCatalog));
router.get('/category/:categoryId', asyncHandler(listProductsByCategory));
router.get('/:slug', asyncHandler(getProductBySlug));
router.post('/', requireAdmin, asyncHandler(createProduct));
router.put('/:productId', requireAdmin, asyncHandler(updateProduct));
router.delete('/:productId', requireAdmin, asyncHandler(deleteProduct));

module.exports = router;
